// Парсинг JSON от ИИ + проверка на галлюцинации
// Цель: убедиться, что ИИ не выдумал и не исказил данные

const aiResponse = $json.choices[0].message.content;

// 1. Чистим возможную markdown-обёртку ```json ... ```
const cleaned = aiResponse
  .replace(/^```(json)?\s*/i, '')
  .replace(/\s*```$/, '')
  .trim();

// 2. Парсим JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Не удалось распарсить JSON от ИИ',
      parse_error: e.message,
      raw_ai_response: aiResponse
    }
  }];
}

// 3. Получаем исходные данные заявки
const original = $('Webhook — прием заявки').item.json.body;

// 4. Проверки целостности
const requiredFields = [
  'client_name', 'contact', 'email', 'request_type',
  'request_summary', 'payment_description', 'amount', 'priority'
];
const missingFields = requiredFields.filter(f => !(f in parsed));

const checks = {
  has_all_required_fields: missingFields.length === 0,
  missing_fields: missingFields,
  amount_unchanged: String(parsed.amount).trim() === String(original.amount).trim(),
  email_unchanged: parsed.email === original.email,
  contact_unchanged: parsed.contact === original.contact,
  priority_valid: ['high', 'medium', 'low'].includes(parsed.priority)
};

const allPassed = checks.has_all_required_fields
  && checks.amount_unchanged
  && checks.email_unchanged
  && checks.contact_unchanged
  && checks.priority_valid;

// 5. Финальный результат
return [{
  json: {
    success: true,
    data: parsed,
    validation: {
      ...checks,
      all_checks_passed: allPassed,
      original_amount: original.amount,
      ai_amount: parsed.amount
    }
  }
}];

// Существующие строки из xlsx (могут быть пустыми)
const existingRows = $input.all()
  .map(item => item.json)
  .filter(r => r && Object.keys(r).length > 0);

// Данные новой заявки из узла парсинга
const aiData = $('Code — парсинг и проверка').item.json.data;

// Форматируем новую строку с теми же ключами, что в существующей таблице
const today = new Date().toISOString().split('T')[0];

const newRow = {
  "Дата": today,
  "Имя": aiData.client_name,
  "Контакт": aiData.contact,
  "Адрес электронной почты": aiData.email,
  "Тип заявки": aiData.request_type,
  "Описание": aiData.request_summary,
  "Сумма": aiData.amount,
  "Статус": "ожидает оплату",
  "Платёжная ссылка": ""
};

return [...existingRows, newRow].map(row => ({ json: row }));
